UPDATE teacher_job_posting
subject_id = #{subjectId}, title = #{title}, description = #{description}, price_per_hour = #{pricePerHour}, mode = #{mode}, city = #{city}, available_time = #{availableTime}, max_students = #{maxStudents}, status = #{status}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT
    id, tutor_id, subject_id, title, description, price_per_hour, mode, city, available_time,
    max_students, status, create_time, update_time
FROM teacher_job_posting
WHERE tutor_id = #{tutorId}

    AND id < #{cursor}

ORDER BY id DESC
LIMIT #{pageSize}

SELECT
    id, tutor_id, subject_id, title, description, price_per_hour, mode, city, available_time,
    max_students, status, create_time, update_time
FROM teacher_job_posting
WHERE status = 1

    AND subject_id = #{subjectId}


    AND mode = #{mode}


    AND city = #{city}


    AND id < #{cursor}

ORDER BY id DESC
LIMIT #{pageSize}

SELECT
    id, tutor_id, subject_id, title, description, price_per_hour, mode, city, available_time,
    max_students, status, create_time, update_time
FROM teacher_job_posting
WHERE status = 1

    AND subject_id = #{subjectId}


    AND mode = #{mode}


    AND city = #{city}


    AND id < #{cursor}



        ORDER BY price_per_hour ASC, id DESC


        ORDER BY price_per_hour DESC, id DESC


        ORDER BY id DESC


LIMIT #{pageSize}

SELECT
    tutor_id,
    MAX(id) AS cursor_key
FROM teacher_job_posting
WHERE status = 1

    AND subject_id = #{subjectId}


    AND mode = #{mode}


    AND city = #{city}

GROUP BY tutor_id

    HAVING MAX(id) < #{cursor}

ORDER BY cursor_key DESC
LIMIT #{pageSize}

SELECT id, tutor_id, subject_id, title, description, price_per_hour, mode, city, available_time, max_students, status, create_time, update_time FROM ( SELECT t.*, ROW_NUMBER() OVER (PARTITION BY tutor_id ORDER BY id DESC) AS rn FROM teacher_job_posting t WHERE status = 1 AND tutor_id IN
#{tid}
) x WHERE x.rn <= #{topN} ORDER BY tutor_id, id DESC
